import { Registry } from '../core/zc-registry';
import { $ZCG } from '../core/zcglobal';
import { d3_selectAll } from '../core/d3-constants';
import { defined, invokeFunction, splat } from '../utils/zcutils';
import { createElement, getTextBoundByDOM, applyFont } from '../utils/zcsvgutils';
import { dataLabelTextContent } from './datalabel-content';
import { getTextBound } from '../axis/textBound';

export function MeasureDataLabel(data, _args) {
    let { config, chartObj, renderMode, accessor = dataLabelTextContent(chartObj, null, config) } = _args,
        systemConfig = chartObj.systemConf,
        fullConfig = [config, systemConfig.chart.plot.datalabels, systemConfig.chart, systemConfig.canvas, $ZCG];

    return MeasureText(data, { config: fullConfig, accessor, renderMode });
}

export function MeasureText(data, _args) {
    let { config, renderMode, accessor: content } = _args,
        { contentType, multiLine } = content,
        renderDOM = contentType == 'html' || multiLine || renderMode === 'svg',
        element;
    config = splat(config);

    if (renderDOM) {
        element = createElement('text', '.dummy-text', [1], d3_selectAll('svg.svgPattern'));
        element.style('opacity', 0);
        applyFont(element, config);
    }

    let size = data.map((d, i) => {
        var text = invokeFunction(content, d, i);
        if (renderDOM) {
            return getTextBoundByDOM(element, text, contentType, multiLine);
        } else {
            var font = applyFont(null, config),
                fontSize = defined(font['font-size']) ? parseFloat(font['font-size']) : null;
            return getTextBound(text, fontSize, font['font-family'], null, null, font['font-style'], font['font-weight']);
        }
    });

    if (element) {
        element.remove();
    }

    return size;
}

Registry.setComponent('dataLabel.measureText', MeasureDataLabel);
